+    ...init,
+    credentials: "include",
+    headers: {
+      "Content-Type": "application/json",
+      ...(init.headers ?? {}),
+    },
+  });
+
+  return {
+    ok: response.ok,
+    status: response.status,
+    body: (await parseResponse(response)) as T | null,
+  };
